import axios from 'axios';
const baseURL = "https://api.example.com";
let token;

export const setAuthToken = (newToken) => {
    if(newToken){
        token = newToken;
    } else {
        token = null;
    }
};

export const authenticateUser = async (username, password) => {
  try{
      let res=await axios.post(`${baseURL}/login`, {username: username, password: password});
       setAuthToken(res.data.token); // setting the auth token
       return true;
    } catch (error) {
        console.log("Authentication Error: ", error);
        return false;
    }
};

export const getUserProfile = async () => {
  try{
      let res=await axios.get(`${baseURL}/user_profile`,{headers: {"Authorization" : `Bearer ${token}`}});
       return res.data; // returning user data
    } catch (error) {
        console.log("Profile fetch Error: ", error);
        return null;
    }
};

export const updateUserData = async (userId, updatedUserDetails) => {
  try{
      let res=await axios.put(`${baseURL}/update_profile/${userId}`, updatedUserDetails,{headers: {"Authorization" : `Bearer ${token}`}});
       return true; // return success status after data update
    } catch (error) {
        console.log("Data Update Error: ", error);
        return false;
    }
};